def solve(well_type, depth, length=None):
    if well_type == 'vertical':
        return f"Drilling a vertical well to a depth of {depth} meters."
    elif well_type == 'horizontal':
        if length is None:
            raise ValueError("Length must be provided for horizontal wells.")
        return f"Drilling a horizontal well to a depth of {depth} meters and a length of {length} meters."
    else:
        raise ValueError("Invalid well type. Must be 'vertical' or 'horizontal'.")

# Minimal unit tests for critical behaviors
def test_vertical_well():
    assert solve('vertical', 100) == "Drilling a vertical well to a depth of 100 meters."

def test_horizontal_well():
    assert solve('horizontal', 100, 200) == "Drilling a horizontal well to a depth of 100 meters and a length of 200 meters."

def test_horizontal_well_missing_length():
    try:
        solve('horizontal', 100)
    except ValueError as e:
        assert str(e) == "Length must be provided for horizontal wells."

def test_invalid_well_type():
    try:
        solve('diagonal', 100)
    except ValueError as e:
        assert str(e) == "Invalid well type. Must be 'vertical' or 'horizontal'."

# Run tests
test_vertical_well()
test_horizontal_well()
test_horizontal_well_missing_length()
test_invalid_well_type()
